# Test 1: User API
echo "Test 1: User API Access"
USER_RESULT=$(curl -s -X GET "https://api.clickup.com/api/v2/user" -H "Authorization: $TOKEN" | jq -r '.user.username // .err // "ERROR"')
if [ "$USER_RESULT" != "ERROR" ] && [ "$USER_RESULT" != "null" ]; then
  echo "✅ PASS: User API - $USER_RESULT"
else
  echo "❌ FAIL: User API - Token invalid or expired"
  exit 1
fi
echo ""

# Test 2: Workspace API
echo "Test 2: Workspace Access"
WORKSPACE_RESULT=$(curl -s -X GET "https://api.clickup.com/api/v2/team/$WORKSPACE_ID" -H "Authorization: $TOKEN" | jq -r '.team.name // .err // "ERROR"')
if [ "$WORKSPACE_RESULT" != "ERROR" ] && [ "$WORKSPACE_RESULT" != "null" ]; then
  echo "✅ PASS: Workspace API - $WORKSPACE_RESULT"
else
  echo "❌ FAIL: Workspace API - No access to workspace $WORKSPACE_ID"
  exit 1
fi
echo ""

# Test 3: List Read Access
echo "Test 3: List Read Access"
LIST_RESULT=$(curl -s -X GET "https://api.clickup.com/api/v2/list/$LIST_ID" -H "Authorization: $TOKEN" | jq -r '.list.name // .err // "ERROR"')
if [ "$LIST_RESULT" != "ERROR" ] && [ "$LIST_RESULT" != "null" ]; then
  echo "✅ PASS: List Read - $LIST_RESULT"
else
  echo "❌ FAIL: List Read - No access to list $LIST_ID"
  exit 1
fi
echo ""

# Test 4: Task Creation (CRITICAL)
echo "Test 4: Task Creation (WRITE PERMISSION)"
TASK_NAME="Test Task $(date +%s)"
CREATE_RESULT=$(curl -s -X POST "https://api.clickup.com/api/v2/list/$LIST_ID/task" \
  -H "Authorization: $TOKEN" \
  -H "Content-Type: application/json" \
  -d "{\"name\": \"$TASK_NAME\", \"markdown_description\": \"Test\", \"status\": \"to do\"}" | jq -r '.id // .err // "ERROR"')

if [ "$CREATE_RESULT" != "ERROR" ] && [ "$CREATE_RESULT" != "null" ] && [[ "$CREATE_RESULT" =~ ^[0-9a-z]+$ ]]; then
  echo "✅ PASS: Task Creation - Task ID: $CREATE_RESULT"
  echo "✅ Token has WRITE permissions"
  
  # Clean up test task
  echo "Cleaning up test task..."
  curl -s -X DELETE "https://api.clickup.com/api/v2/task/$CREATE_RESULT" -H "Authorization: $TOKEN" > /dev/null
  echo "✅ Test task deleted"
else
  echo "❌ FAIL: Task Creation"
